using System.Reflection;

var dllPath = "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net8.0/Microsoft.Agents.AI.dll";
var asm = Assembly.LoadFrom(dllPath);

// Find ChatClientAgent
var chatClientAgentType = asm.GetType("Microsoft.Agents.AI.ChatClientAgent");
Console.WriteLine("=== ChatClientAgent ===");
Console.WriteLine($"Type: {chatClientAgentType}");

if (chatClientAgentType != null) {
    Console.WriteLine("\n-- Constructors --");
    foreach (var ctor in chatClientAgentType.GetConstructors(BindingFlags.Public | BindingFlags.Instance)) {
        var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {chatClientAgentType.Name}({parms})");
    }

    Console.WriteLine("\n-- Public Methods (first 30) --");
    var methods = chatClientAgentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Take(30);
    foreach (var method in methods) {
        var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
        Console.WriteLine($"  {method.Name}({parms}) : {method.ReturnType.Name}");
    }
}

// Find AIAgent
var aiAgentType = asm.GetType("Microsoft.Agents.AI.AIAgent");
Console.WriteLine("\n=== AIAgent ===");
Console.WriteLine($"Type: {aiAgentType}");
if (aiAgentType != null) {
    Console.WriteLine($"IsAbstract: {aiAgentType.IsAbstract}");
    Console.WriteLine($"IsInterface: {aiAgentType.IsInterface}");

    Console.WriteLine("\n-- Abstract Methods --");
    var methods = aiAgentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    foreach (var method in methods) {
        if (method.IsAbstract) {
            var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name}"));
            Console.WriteLine($"  {method.Name}({parms}) : {method.ReturnType.Name}");
        }
    }
}

// Find AgentInvokeOptions
var invokeOptionsType = asm.GetType("Microsoft.Agents.AI.AgentInvokeOptions");
Console.WriteLine("\n=== AgentInvokeOptions ===");
if (invokeOptionsType != null) {
    Console.WriteLine($"Type: {invokeOptionsType}");
    Console.WriteLine("\n-- Properties --");
    foreach (var prop in invokeOptionsType.GetProperties()) {
        Console.WriteLine($"  {prop.Name} : {prop.PropertyType.Name}");
    }
}

// Find ChatClientAgentOptions
var chatOptionsType = asm.GetType("Microsoft.Agents.AI.ChatClientAgentOptions");
Console.WriteLine("\n=== ChatClientAgentOptions ===");
if (chatOptionsType != null) {
    Console.WriteLine($"Type: {chatOptionsType}");
    Console.WriteLine("\n-- Properties --");
    foreach (var prop in chatOptionsType.GetProperties()) {
        Console.WriteLine($"  {prop.Name} : {prop.PropertyType.Name}");
    }
}

// Find interfaces
Console.WriteLine("\n=== All Agent-Related Types ===");
var types = asm.GetTypes().Where(t => t.Name.Contains("Agent")).OrderBy(t => t.Name);
foreach (var type in types.Take(30)) {
    var isInterface = type.IsInterface ? "[I]" : type.IsAbstract ? "[A]" : "[C]";
    Console.WriteLine($"  {isInterface} {type.FullName}");
}
EOF
