using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build IChatClient from the OpenAI provider
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
var notepad = new Notepad();

// Register tools via AIFunctionFactory
IList<AITool> tools =
[
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
];

// Create the research agent with instructions and tools
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you:
        1. Search the web for relevant information using multiple targeted queries.
        2. Take notes on the key findings from each search.
        3. After gathering enough information, review your notes and produce a
           well-structured summary with the key points, organized by theme.
        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// Prompt the user for a research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Run the agent with an iteration-capped chat option
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// ------------------------------------------------------------------
// Tool: Web search (uses a simple HTTP scrape as a stand-in)
// ------------------------------------------------------------------
static partial class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Searches the web for information on a query and returns a summary of the top results.")]
    public static async Task<string> SearchAsync(
        [Description("The search query to look up")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            // Extract text snippets from the HTML response
            var text = StripHtml(html);
            var lines = text.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .Where(l => l.Length > 30)
                .Take(15);

            var result = string.Join("\n", lines);
            return string.IsNullOrWhiteSpace(result)
                ? $"No results found for '{query}'."
                : $"Search results for '{query}':\n{result}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WhitespaceRegex().Replace(text, " ");
        return System.Net.WebUtility.HtmlDecode(text);
    }

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();
}

// ------------------------------------------------------------------
// Tool: Notepad for taking and retrieving research notes
// ------------------------------------------------------------------
class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note. Use this to record key findings from search results.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");

        return sb.ToString();
    }
}

